import{createHash}from"node:crypto";import{toRelative}from"../util/path.js";import{getIssuePrefix,getIssueTypeTitle}from"./util/util.js";export default async({report:e,issues:t,cwd:i})=>{const o=[];for(const[n,s]of Object.entries(e)){if(!s)continue;const e="files"===n?"_files":n;for(const n of flatten(t[e])){const{filePath:t}=n;"duplicates"===e&&n.symbols?o.push(...n.symbols.map(o=>({type:"issue",check_name:getIssueTypeTitle(e),description:getSymbolDescription({type:n.type,symbol:o,parentSymbol:n.parentSymbol}),categories:["Duplication"],location:createLocation(t,i,o.line,o.col),severity:convertSeverity(n.severity),fingerprint:createFingerprint(t,i,o.symbol)}))):o.push({type:"issue",check_name:getIssueTypeTitle(e),description:getIssueDescription(n),categories:["Bug Risk"],location:createLocation(t,i,n.line,n.col),severity:convertSeverity(n.severity),fingerprint:createFingerprint(t,i,n.symbol)})}}const n=JSON.stringify(o);process.stdout._handle?.setBlocking?.(!0),process.stdout.write(`${n}\n`)};function flatten(e){return Object.values(e).flatMap(Object.values)}function convertSeverity(e){switch(e){case"error":return"major";case"warn":return"minor";default:return"info"}}function getIssueDescription({type:e,symbol:t,symbols:i,parentSymbol:o}){const n=i?`${i.map(e=>e.symbol).join(", ")}`:t;return`${getIssuePrefix(e)}: ${n}${o?` (${o})`:""}`}function getSymbolDescription({type:e,symbol:t,parentSymbol:i}){return`${getIssuePrefix(e)}: ${t.symbol}${i?` (${i})`:""}`}function createLocation(e,t,i,o){return void 0!==o?{path:toRelative(e,t),positions:{begin:{line:i??0,column:o},end:{line:i??0,column:o}}}:{path:toRelative(e,t),lines:{begin:i??0,end:i??0}}}function createFingerprint(e,t,i){const o=createHash("md5");return o.update(toRelative(e,t)),o.update(i),o.digest("hex")}